Bevy main

## What you did

```
use bevy::{
    prelude::*,
    render::camera::RenderTarget,
    window::{WindowRef, WindowResolution},
};
use bevy_render::view::RenderLayers;

fn main() {
    App::new()
        .add_plugins(DefaultPlugins.set(WindowPlugin {
            primary_window: Some(Window {
                resolution: WindowResolution::new(1000., 1000.).with_scale_factor_override(1.),
                title: "Window 1".to_string(),
                ..default()
            }),
            ..default()
        }))
        .add_systems(Startup, setup)
        .run();
}

fn setup(mut commands: Commands) {
    // The primary window is the default camera target and 0 is the default render layer, there's no need to set these normally
    // the explicitness is just to make this example as clear as possible.


    commands.spawn((
        Camera2d::default(),
        Camera {
            target: RenderTarget::Window(WindowRef::Primary),
            ..default()
        },
        RenderLayers::layer(0),
    ));

    // Spawn a second window
    let window_2 = commands
        .spawn(Window {
            title: "Window 2".to_owned(),
            resolution: WindowResolution::new(1000., 1000.).with_scale_factor_override(10.),
            ..default()
        })
        .id();

    commands.spawn((
        Camera2d::default(),
        Camera {
            target: RenderTarget::Window(WindowRef::Entity(window_2)),
            ..default()
        },
        RenderLayers::layer(1),
    ));

    // Text drawn to window 1
    commands.spawn((Text2d::new("Window 1"), RenderLayers::layer(0)));

    // Text drawn to window 2
    commands.spawn((Text2d::new("Window 2"), RenderLayers::layer(1)));
}
```

## What went wrong

<img width="501" alt="Image" src="https://github.com/user-attachments/assets/8043198a-bf3a-4336-a929-26fb3b7540b7" />

<img width="501" alt="Image" src="https://github.com/user-attachments/assets/c6e546f7-381b-4aba-889a-713547d48338" />

The text in the second window is extremely pixelated because it uses font atlases generated for the primary window's scale factor of 1 instead of the secondary windows scale factor of 9.

## Additional information
* `update_text2d_layout` uses the scale factor of the primary window or if can't find a primary window it uses a scale factor of 1 for generating the font texture atlases.
* `extract_text2d_sprite` queues an `ExtractedSprite` for each glyph. 

Each `ExtractedSprite` can be drawn to multiple different render targets depending on the `RenderLayers` settings. So even if we created multiple different font texture atlases for each render target, there's no existing mechanism for us to tell the renderer to use a different texture depending on the render target.

