```
use bevy::{
    dev_tools::fps_overlay::{FpsOverlayConfig, FpsOverlayPlugin, FrameTimeGraphConfig},
    prelude::*,
    text::FontSmoothing,
};

fn main() -> AppExit {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_plugins(FpsOverlayPlugin {
            config: FpsOverlayConfig {
                text_config: TextFont {
                    // Here we define size of our overlay
                    font_size: 42.0,
                    // If we want, we can use a custom font
                    font: default(),
                    // We could also disable font smoothing,
                    font_smoothing: FontSmoothing::default(),
                    ..default()
                },
                // We can also change color of the overlay
                text_color: Color::srgb_u8(10, 0, 1),
                // We can also set the refresh interval for the FPS counter
                refresh_interval: core::time::Duration::from_millis(100),
                enabled: true,
                frame_time_graph_config: FrameTimeGraphConfig {
                    enabled: false,
                    // The minimum acceptable fps
                    min_fps: 30.0,
                    // The target fps
                    target_fps: 60.0,
                },
            },
        })
        .insert_resource(GameData::new())
        .add_systems(Startup, setup)
        .add_systems(Update, on_update)
        .run()
}

const X_EXTENT: f32 = 1650.;

#[derive(Resource, Default)]
struct GameData {
    big_counter: u64,
    line_counter: u64,
}

impl GameData {
    pub fn new() -> Self {
        Self { ..default() }
    }
}

fn setup(
    mut commands: Commands,
    mut meshes: ResMut<Assets<Mesh>>,
    mut materials: ResMut<Assets<ColorMaterial>>,
) {
    commands.spawn(Camera2d);

    let mut shapes = vec![];
    for _i in 0..600 {
        shapes.push(meshes.add(RegularPolygon::new(5.0, 4)));
    }

    let num_shapes = shapes.len();

    for (i, shape) in shapes.into_iter().enumerate() {
        let color = Color::oklch(0.25, 0.5, 360. * i as f32 / num_shapes as f32);
        commands.spawn((
            Mesh2d(shape),
            MeshMaterial2d(materials.add(color)),
            Transform::from_xyz(
                // Distribute shapes from -X_EXTENT/2 to +X_EXTENT/2.
                -X_EXTENT / 2. + i as f32 / (num_shapes - 1) as f32 * X_EXTENT,
                0.0,
                0.0,
            )
            .with_rotation(Quat::from_rotation_z(-0.5))
            .with_scale(Vec3::new(3.0, 500.0, 1.0)),
        ));
    }
}

fn on_update(
    mut gd: ResMut<GameData>,
    mut materials: ResMut<Assets<ColorMaterial>>,
    keyboard: Res<ButtonInput<KeyCode>>,
) {
    // first is probably background material
    let steps = materials.iter().count();
    if gd.big_counter == 0 {
        println!("Count of materials: {}", steps);
    }
    for i in 0..steps {
        let material_option = materials.iter_mut().nth(i);
        gd.line_counter += 1;
        if let Some(matt) = material_option {
            let hue: f32 = (155.0 + (gd.big_counter as f32 / 10.5) + (i as f32 / 24.0)) % 360.0;
            let light = 1.0_f32 - lfo_seesaw_norm_f32(gd.big_counter as u32, 950, 0.8)
                + lfo_seesaw_norm_f32(gd.line_counter as u32, 80000, 0.15)
                - ((i as f32) * 0.00025);
            let chrom = 0.05_f32 + lfo_seesaw_norm_f32(40_000 + gd.big_counter as u32, 2100, 0.7)
                - lfo_seesaw_norm_f32(gd.big_counter as u32, 1800, 0.4)
                + ((i as f32) * 0.00025);
            matt.1.color = Color::Oklcha(Oklcha::lch(light, chrom, hue));
        }
    }
    gd.big_counter += 1;
    if keyboard.just_pressed(KeyCode::Space) {
        println!("Space pressed {}", gd.big_counter);
    }
}

pub fn lfo_seesaw(n: u32, cycle: u32) -> u32 {
    let double_cycle = cycle * 2;
    let is_descending_or_peak = n % cycle < n % double_cycle;
    let is_peak = n % double_cycle == cycle;
    match (is_descending_or_peak, is_peak) {
        (true, false) => cycle - (n % (cycle)),
        (true, true) => cycle,
        (false, _) => n % cycle,
    }
}

pub fn lfo_seesaw_norm_f32(n: u32, cycle: u32, normalize: f32) -> f32 {
    let lfo = lfo_seesaw(n, cycle) as f32;
    lfo / cycle as f32 * normalize
}
```

bevyengine/bevy#21363.body:
## What problem does this solve or what need does it fill?

Internal components like `Observer` require an `Internal` component with a default query filter.  Default query filters can be ignored by mentioning the type in the query, like `With<Internal>` or `Allows<Internal>`.  But when the filter is added by a required component, the user may not know to mention it!  

```rust
let mut world = World::new();
let entity = world.spawn(Observer::new(|_: On<Insert>| {})).id();

// This seems like it should work, but does not
let mut query = world.query::<&Observer>();
assert!(query.query(&world).get(entity).is_err());

// This is the workaround, but is hard to discover
let mut query = world.query_filtered::<&Observer, Allow<Internal>>();
assert!(query.query(&world).get(entity).is_ok());
```

## What solution would you like?

When a query mentions a component that *requires* a component with a default query filter, that filter should be ignored.

