use std::time::Duration;

use bevy::{prelude::*, time::common_conditions::on_timer, ui_widgets::observe};

#[derive(Component)]
struct MyEntity;

#[derive(EntityEvent)]
struct MyEvent(Entity);

fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .add_systems(Startup, spawn_entity)
        .add_systems(
            Update,
            send_event_every_second.run_if(on_timer(Duration::from_secs(1))),
        )
        .run();
