fn spawn_entity(mut commands: Commands) {
    let dynamic_string = String::from("Hello, Bevy!");
    info!("Dynamic string before closure: '{}'", dynamic_string);
    commands.spawn((
        MyEntity,
        Name::new("My Spawned Entity"),
        observe(move |_trigger: On<MyEvent>| {
            info!("Dynamic string inside closure: '{}'", dynamic_string);
