        .add_plugins(DefaultPlugins)
        .add_systems(Startup, setup)
        .add_systems(Update, update)
        .run();
}

#[derive(Resource)]
struct ImageHandle(Handle<Image>);

#[derive(Resource)]
struct MaterialHandle(Handle<StandardMaterial>);

fn setup(
    mut commands: Commands,
    mut meshes: ResMut<Assets<Mesh>>,
    mut materials: ResMut<Assets<StandardMaterial>>,
    mut images: ResMut<Assets<Image>>,
) {
    let image_h = images.add(create_test_image([255, 0, 255, 255]));
    let material_h = materials.add(StandardMaterial::from(image_h.clone()));
    commands.insert_resource(ImageHandle(image_h));
    commands.insert_resource(MaterialHandle(material_h.clone()));
    commands.spawn((
        Mesh3d(meshes.add(Plane3d::default().mesh().size(20.0, 20.0))),
        MeshMaterial3d(material_h),
    ));
    commands.spawn((
        Camera3d::default(),
        Transform::from_xyz(0.0, 12.0, 0.0).looking_at(Vec3::ZERO, Vec3::Z),
    ));
    commands.spawn(Text::new(""));
}

fn update(
    mut materials: ResMut<Assets<StandardMaterial>>,
    mut images: ResMut<Assets<Image>>,
    image_h: Res<ImageHandle>,
    material_h: Res<MaterialHandle>,
    frame_count: Res<FrameCount>,
    mut text: Single<&mut Text>,
) {
    let colors = [[255, 0, 0, 255], [0, 255, 0, 255], [0, 0, 255, 255]];
    let names = ["RED", "GREEN", "BLUE"];
    let n = 150;
    if frame_count.0 % n as u32 == 0 {
        let idx = ((frame_count.0 / n) as usize) % colors.len();
        let color = colors[idx];
        text.0 = names[idx].to_string();
        println!("UPDATE! {color:?}");

        // Update image at handle
        *images.get_mut(&image_h.0).unwrap() = create_test_image(color);

        // Touch material to trigger change detection
